from confluent_kafka import Consumer

consumer = Consumer({
    'bootstrap.servers': 'localhost:9092',
    'group.id': 'order-events-group',
    'auto.offset.reset': 'earliest',
    'enable.auto.commit': False,  # Manual commit after processing
})

consumer.subscribe(['orders'])

while True:
    msg = consumer.poll(1.0)
    if msg is None or msg.error():
        continue

    try:
        process_order(msg.value())           # Process first
        consumer.commit(asynchronous=False)  # Then commit offset
    except Exception as e:
        log_error(e)
        # Do NOT commit — message will be re-delivered

# WRONG — silently swallows failures and loses messages
try:
    process(msg)
    consumer.commit()
except Exception:
    consumer.commit()  # Still commits even on failure!

# CORRECT — only commit on success
try:
    process(msg)
    consumer.commit()
except Exception as e:
    log_error(e)
    # No commit — message will be re-delivered

